/**
 * Options bag for `Aura.toast()`.
 *
 * @example
 * ```ts
 * Aura.toast("Saved!");  // shorthand — info variant, 4 s auto-dismiss
 * Aura.toast({ message: "Upload complete", variant: "success", duration: 3000,
 *   onClose: () => refresh() });
 * Aura.toast({ message: "Session ended", variant: "warning", duration: 0 }); // persistent
 * ```
 */
export interface AuraToastOptions {
  /** The notification message text. */
  message: string;
  /** Visual + ARIA variant (default "info"). */
  variant?: "info" | "success" | "warning" | "danger" | "notification";
  /** Auto-dismiss delay in ms (default 4000; 0 = persistent). */
  duration?: number;
  /** Called when the toast is dismissed (timeout or user action). */
  onClose?: () => void;
}

