  ready(fn: (doc: Document) => void): void;
  /** Register a mount callback invoked on initial load and on every subsequent HTMX swap or MutationObserver settle. Use this for per-element enhancements that must re-run when new DOM arrives. */
  onMount(fn: (root: Document | Element) => void): void;
