  /** Environment capability flags detected at load — each is a function returning a live boolean. */
  env: Readonly<{ reducedMotion(): boolean; coarsePointer(): boolean; [key: string]: () => boolean }>;
  /** Show a toast notification; returns the created element. `Aura.toast.flush()` immediately dismisses all queued and visible toasts. */
  toast: ((input: string | AuraToastOptions) => Element) & { flush(): void };
  /** Runtime theming API — set colours, modes, wallpapers, named themes. */
  theme: AuraThemeAPI;
  /** Programmatic dialog API — open/close/closeAll `<aura-dialog>` elements imperatively. */
  dialog: AuraDialogAPI;
  /** Tooltip API — show, hide, or imperatively attach tooltip text to an element. */
  tooltip: AuraTooltipAPI;
  /** Programmatic menu API — open menus at a coordinate or anchored to an element, close all, query open count. */
  menu: AuraMenuAPI;
  /** Form-guard API — check/mark/clear dirty state across `<aura-form>` elements with `data-aura-guard`. */
  formGuard: AuraFormGuardAPI;
  /** Copy-to-clipboard API — `copyText`, `textFor`, `injectCodeButtons`, and `announce`. */
